import json, urllib.request
for endpoint in ['pages','users','themes','types','media','comments']:
    url = f'http://localhost:80/?rest_route=/wp/v2/{endpoint}'
    try:
        with urllib.request.urlopen(url, timeout=10) as r:
            data = r.read()
        items = json.loads(data.decode())
        print(endpoint, len(items))
        if isinstance(items, list):
            for it in items[:5]:
                print(' -', it.get('id'), it.get('slug') or it.get('name') or it.get('title',{}).get('rendered'))
    except Exception as e:
        print(endpoint, 'error', e)

