import urllib.request
paths=['api','rce','debug','admin','uploads','files','backup','backups','old','test','dev','shell','cmd','exec','eval','wp-json','wp-sitemap.xml','sitemap.xml','db','config','config.php','wp-admin/install.php','readme.html','license.txt','wp-admin/','wp-content/','wp-includes/','plugins','assets','static']
base='http://localhost:80/'
for p in paths:
    url=base+p
    try:
        r=urllib.request.urlopen(url, timeout=5)
        code=r.getcode()
        print(f"{p} -> {code}")
    except Exception as e:
        if hasattr(e,'code'):
            print(f"{p} -> {e.code}")
        else:
            print(f"{p} -> error {e}")
